-- 過去問アップローダー 仮のマスタデータ
--
-- 出典: 岡山大学(Okayama University)公式サイトおよび各学部カリキュラム・マップ(PDF)
--   https://www.okayama-u.ac.jp/tp/faculty/index.html ほか
-- 注意:
--   学部・学科・科目名は上記の実在情報に基づく．
--   grade(開講学年)はカリキュラム・マップの記載を採用(範囲表記は下限を採用)．
--   term(学期)は公式資料に科目単位の前期/後期の別が無かったため「仮」の値(1=前期系,2=後期系)を割り当てている．
--   UUIDは本マスタ用に固定採番した仮の値である．

CREATE TABLE IF NOT EXISTS faculties (
    id   TEXT PRIMARY KEY,
    name TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS majors (
    id         TEXT PRIMARY KEY,
    name       TEXT NOT NULL,
    faculty_id TEXT NOT NULL REFERENCES faculties(id)
);

CREATE TABLE IF NOT EXISTS subjects (
    id         TEXT PRIMARY KEY,
    name       TEXT NOT NULL,
    faculty_id TEXT NOT NULL REFERENCES faculties(id),
    major_id   TEXT NOT NULL REFERENCES majors(id),
    grade      INTEGER NOT NULL CHECK (grade BETWEEN 1 AND 9),
    term       INTEGER NOT NULL CHECK (term BETWEEN 1 AND 4)
);

CREATE INDEX IF NOT EXISTS idx_majors_faculty   ON majors(faculty_id);
CREATE INDEX IF NOT EXISTS idx_subjects_faculty ON subjects(faculty_id);
CREATE INDEX IF NOT EXISTS idx_subjects_major   ON subjects(major_id);

